type BoardState = 'normal' | 'dragging' | 'selected' | 'mana' | 'search' | 'stack' | 'commander' | 'damage' | 'waiting' | 'reconnect';
const phaseNames = ['Beginning', 'Main', 'Combat', 'Second Main', 'End'];
const logEvents = ['Player casts Verdant Oath', 'Ability goes on the stack', 'AI chooses no blocks', 'Commander tax increases', 'Damage dealt: 3'];
const handCards = [{
  name: 'Verdant Oath',
  type: 'Sorcery',
  color: 'from-emerald-500/45'
}, {
  name: 'Glasswater Adept',
  type: 'Creature',
  color: 'from-sky-500/45'
}, {
  name: 'Sunlit Bastion',
  type: 'Land',
  color: 'from-amber-400/40'
}, {
  name: 'Binding Root',
  type: 'Instant',
  color: 'from-lime-500/40'
}, {
  name: 'Cinder Vow',
  type: 'Removal',
  color: 'from-red-500/38'
}, {
  name: 'Relic Compass',
  type: 'Artifact',
  color: 'from-stone-300/36'
}];
const prompts: Record<Exclude<BoardState, 'normal' | 'dragging' | 'selected'>, {
  title: string;
  eyebrow: string;
  body: string;
  choices: string[];
  disabled?: string;
}> = {
  mana: {
    eyebrow: 'MM.ManaPrompt',
    title: 'Pay Mana Cost',
    body: 'Choose exact sources for Verdant Oath. No colorless or zero amount is selected by default.',
    choices: ['Forest', 'Island', 'Sol Ring', 'Treasure'],
    disabled: 'Submit disabled until exact payment is valid'
  },
  search: {
    eyebrow: 'MM.SearchPrompt',
    title: 'Search Library',
    body: 'Select a matching card. The first result is not auto-picked.',
    choices: ['Creature', 'Land', 'Instant', 'Commander'],
    disabled: 'Submit disabled until one legal card is chosen'
  },
  stack: {
    eyebrow: 'MM.PromptOverlay',
    title: 'Respond to Stack',
    body: 'Triggered ability is waiting. Choose a response or pass priority.',
    choices: ['Inspect source', 'Choose target', 'Pass priority'],
    disabled: 'Primary action changes to Resolve only when legal'
  },
  commander: {
    eyebrow: 'MM.CommanderReplacementPrompt',
    title: 'Commander Replacement',
    body: 'Commander would move to graveyard. Command zone is not selected by default.',
    choices: ['Move to graveyard', 'Move to command zone'],
    disabled: 'Submit disabled until Caleb chooses a destination'
  },
  damage: {
    eyebrow: 'MM.DamageAssignmentPrompt',
    title: 'Assign Damage',
    body: 'Allocate 5 damage. Pile 1 and zero assignments are not defaulted.',
    choices: ['Blocker A: 0/3', 'Blocker B: 0/2', 'Player: locked'],
    disabled: 'Submit disabled until lethal/order rules are satisfied'
  },
  waiting: {
    eyebrow: 'MM.AIThinkingStatus',
    title: 'AI Thinking',
    body: 'XMage bridge is waiting for the opponent decision. Board remains readable.',
    choices: ['AI evaluating attacks', 'Priority held by opponent', 'Reconnect status safe'],
    disabled: 'No hidden default action while waiting'
  },
  reconnect: {
    eyebrow: 'MM.UnsupportedPromptFallback',
    title: 'Bridge Unavailable',
    body: 'Connection to the rules engine paused. Unknown prompt fallback is visible and safe.',
    choices: ['Retry bridge', 'View last log', 'Keep local board locked'],
    disabled: 'No game action is submitted until bridge confirms state'
  }
};
function MiniCard({
  name,
  type,
  small,
  tapped,
  selected,
  invalid
}: {
  name: string;
  type: string;
  small?: boolean;
  tapped?: boolean;
  selected?: boolean;
  invalid?: boolean;
}) {
  return <div className={['mm-card relative flex shrink-0 flex-col justify-between p-1.5', small ? 'h-[58px] w-[42px]' : 'h-[72px] w-[52px]', tapped ? 'rotate-90' : '', selected ? 'mm-blue-glow -translate-y-3' : '', invalid ? 'opacity-45 saturate-50' : ''].join(' ')}>

      <div className="mm-card-art h-7 rounded-[4px] border border-amber-200/20" />
      <div className="truncate text-[7px] font-semibold leading-3 text-amber-50">{name}</div>
      <div className="text-[6px] uppercase leading-none text-amber-200/70">{type}</div>
    </div>;
}
function OpponentHUD() {
  return <section data-mm-layer="MM.OpponentVerticalHUD" className="mm-glass absolute left-5 top-5 z-20 w-[82px] rounded-md p-2">
      <div className="flex items-center gap-1.5">
        <div className="grid h-8 w-8 place-items-center rounded-full border border-amber-300/55 bg-emerald-950 text-[13px]">AI</div>
        <div>
          <div className="truncate text-[9px] font-bold text-amber-100">Ashen Sage</div>
          <div className="mm-title text-[16px] font-bold leading-none text-amber-300">22</div>
        </div>
      </div>
      <div className="mt-1.5 grid grid-cols-2 gap-1 text-[7px] text-amber-100/90">
        <span className="rounded bg-amber-950/50 px-1">CMD 1</span>
        <span className="rounded bg-amber-950/50 px-1">Hand 5</span>
        <span className="rounded bg-amber-950/50 px-1">Lib 63</span>
        <span className="rounded bg-amber-950/50 px-1">GY 4</span>
        <span className="rounded bg-amber-950/50 px-1">Ex 1</span>
        <span className="rounded bg-emerald-900/60 px-1">0:42</span>
      </div>
    </section>;
}
function RightRail() {
  return <aside data-mm-layer="MM.RightPhaseRail" className="absolute right-5 top-5 z-20 flex w-[82px] flex-col gap-1">
      <div className="mm-glass rounded-md p-1.5">
        {phaseNames.map(phase => <div key={phase} className={`mb-1 rounded px-1 py-0.5 text-[7px] ${phase === 'Combat' ? 'bg-cyan-300/18 text-cyan-100 mm-blue-glow' : 'text-amber-100/72'}`}>
            {phase}
          </div>)}
      </div>
      <button data-mm-layer="MM.PrimaryFlowButton" className="mm-title rounded-md border border-amber-300/60 bg-amber-500/85 px-2 py-1.5 text-[12px] font-bold text-stone-950 shadow-lg">
        Pass
      </button>
    </aside>;
}
function GameLog() {
  return <section data-mm-layer="MM.RightTransparentGameLog" className="mm-glass absolute bottom-[86px] right-5 z-20 w-[150px] rounded-md p-2">
      <div className="mb-1 flex items-center justify-between">
        <span className="mm-title text-[9px] font-semibold text-amber-200">Log</span>
        <span className="text-[7px] text-cyan-200">expand</span>
      </div>
      <div className="space-y-1">
        {logEvents.map(event => <div key={event} className="truncate border-l border-amber-300/30 pl-1 text-[7px] text-amber-50/82">{event}</div>)}
      </div>
    </section>;
}
function StackIndicator({
  active
}: {
  active?: boolean;
}) {
  return <button data-mm-layer="MM.StackMiniIndicator" className={`mm-glass absolute right-[116px] top-5 z-20 w-[126px] rounded-md px-2 py-1.5 text-left ${active ? 'mm-blue-glow' : ''}`}>
      <div className="flex items-center justify-between">
        <span className="mm-title text-[9px] text-amber-200">Stack</span>
        <span className="rounded bg-cyan-300/20 px-1 text-[8px] text-cyan-100">2</span>
      </div>
      <div className="truncate text-[8px] text-amber-50">Triggered ability</div>
      <div className="truncate text-[7px] text-amber-100/65">source: Relic Compass</div>
    </button>;
}
function ZoneChips() {
  const chips = [['MM.CommandZoneChip', 'Command'], ['MM.GraveyardChip', 'Grave'], ['MM.ExileChip', 'Exile'], ['MM.LibraryChip', 'Library'], ['MM.DebugSheet', 'Gear']];
  return <nav data-mm-layer="MM.ZoneChips" className="absolute bottom-[48px] left-[104px] z-20 flex gap-1">
      {chips.map(([layer, label]) => <button key={layer} data-mm-layer={layer} className="rounded-full border border-amber-300/25 bg-black/28 px-2 py-1 text-[8px] text-amber-100 backdrop-blur">
          {label}
        </button>)}
    </nav>;
}
function HandRail({
  selected
}: {
  selected?: boolean;
}) {
  return <section data-mm-layer="MM.PlayerHandRail" className="absolute bottom-1 left-1/2 z-30 flex h-[93px] w-[500px] -translate-x-1/2 items-end justify-center">
      <div className="absolute bottom-0 h-[54px] w-full rounded-t-[55%] border-t border-amber-300/25 bg-black/18 blur-[0.2px]" />
      {handCards.map((card, index) => <div key={card.name} data-mm-layer={selected && index === 1 ? 'MM.SelectedCardLift' : undefined} className={`relative -ml-2 transition-transform ${index === 0 ? 'ml-0 -rotate-6' : ''} ${index === 1 ? '-rotate-3' : ''} ${index === 2 ? 'rotate-0' : ''} ${index === 3 ? 'rotate-3' : ''} ${index === 4 ? 'rotate-5' : ''} ${index === 5 ? 'rotate-7' : ''}`}>

          <div className={`${selected && index === 1 ? 'mm-blue-glow -translate-y-5 scale-110' : ''}`}>
            <MiniCard name={card.name} type={card.type} />
          </div>
        </div>)}
    </section>;
}
function BattlefieldCards({
  state
}: {
  state: BoardState;
}) {
  return <>
      <div data-mm-layer="MM.OpponentBattlefieldCards" className="absolute left-[172px] top-[64px] z-10 flex items-center gap-3">
        <MiniCard small name="AI land" type="Land" tapped />
        <MiniCard small name="AI land" type="Land" />
        <MiniCard small name="Watcher" type="Creature" invalid={state === 'dragging'} />
        <MiniCard small name="Commander" type="Legend" />
      </div>
      <div data-mm-layer="MM.PlayerBattlefieldCards" className="absolute bottom-[113px] left-[188px] z-10 flex items-end gap-4">
        <MiniCard name="Forest" type="Land" tapped />
        <MiniCard name="Island" type="Land" />
        <MiniCard name="Sol Ring" type="Artifact" tapped />
        <MiniCard name="Commander" type="Legend" selected={state === 'selected'} />
        <MiniCard name="Adept" type="Creature" />
      </div>
    </>;
}
function DropZones() {
  return <div className="pointer-events-none absolute inset-0 z-40">
      <div data-mm-layer="MM.DragDropZoneCast" className="mm-valid-glow absolute left-[265px] top-[128px] grid h-[82px] w-[235px] place-items-center rounded-md border border-emerald-200/80 bg-emerald-400/12 text-[11px] font-semibold text-emerald-100">
        Cast / Play Here
      </div>
      <div data-mm-layer="MM.DragDropZoneBattlefield" className="mm-blue-glow absolute bottom-[112px] left-[250px] grid h-[82px] w-[250px] place-items-center rounded-md border border-cyan-200/75 bg-cyan-400/12 text-[11px] font-semibold text-cyan-100">
        Battlefield Drop
      </div>
      <div data-mm-layer="MM.ValidTargetGlow" className="absolute left-[575px] top-[132px] h-[78px] w-[58px] rounded-lg border border-emerald-200/90 bg-emerald-300/10 shadow-[0_0_22px_rgba(96,255,191,0.55)]" />
      <div data-mm-layer="MM.InvalidTargetDim" className="mm-red-dim absolute left-[660px] top-[82px] h-[96px] w-[92px] rounded-md text-center text-[8px] text-red-100">
        invalid target
      </div>
      <div data-mm-layer="MM.DragGhostCard" className="absolute left-[438px] top-[225px] rotate-[-8deg] opacity-75">
        <MiniCard name="Verdant Oath" type="Dragged" selected />
      </div>
    </div>;
}
function PromptOverlay({
  state
}: {
  state: Exclude<BoardState, 'normal' | 'dragging' | 'selected'>;
}) {
  const prompt = prompts[state];
  const isStack = state === 'stack';
  return <div data-mm-layer="MM.PromptOverlay" className="absolute inset-0 z-50 grid place-items-center bg-black/24">
      <section data-mm-layer={prompt.eyebrow} className="mm-glass w-[420px] rounded-md border-amber-300/35 p-4">
        <div className="text-[8px] uppercase text-cyan-200/90">{prompt.eyebrow}</div>
        <h2 className="mm-title mt-1 text-[21px] font-bold text-amber-100">{prompt.title}</h2>
        <p className="mt-1 text-[11px] leading-4 text-amber-50/82">{prompt.body}</p>
        <div className="mt-3 grid grid-cols-2 gap-2">
          {prompt.choices.map(choice => <button key={choice} className="rounded border border-amber-300/26 bg-stone-950/35 px-2 py-2 text-left text-[10px] text-amber-100">
              {choice}
            </button>)}
        </div>
        {isStack && <div data-mm-layer="MM.StackExpandedSheet" className="mt-3 rounded border border-cyan-200/35 bg-cyan-950/30 p-2 text-[9px] text-cyan-100">
            Full stack sheet: triggered ability, copied spell, priority order.
          </div>}
        <div data-mm-layer="MM.UnsupportedPromptFallback" className="mt-3 rounded bg-black/22 px-2 py-1 text-[8px] text-amber-100/70">
          {prompt.disabled}
        </div>
        <div className="mt-3 flex justify-end">
          <button data-mm-layer="MM.PrimaryFlowButton" disabled className="rounded-md border border-amber-200/20 bg-amber-100/18 px-4 py-2 text-[10px] font-bold text-amber-100/55">
            Submit
          </button>
        </div>
      </section>
    </div>;
}
function StatusPills({
  state
}: {
  state: BoardState;
}) {
  return <div className="absolute left-[104px] top-5 z-20 flex gap-1.5">
      <div data-mm-layer="MM.BridgeStatusPill" className={`rounded-full border px-2 py-1 text-[8px] ${state === 'reconnect' ? 'border-red-300/60 bg-red-950/50 text-red-100' : 'border-emerald-300/35 bg-emerald-950/35 text-emerald-100'}`}>
        {state === 'reconnect' ? 'reconnecting' : 'bridge safe'}
      </div>
      {state === 'waiting' && <div data-mm-layer="MM.AIThinkingStatus" className="rounded-full border border-cyan-200/40 bg-cyan-950/45 px-2 py-1 text-[8px] text-cyan-100">AI thinking</div>}
    </div>;
}
export function MagicMobileBoard({
  state = 'normal',
  frameName = 'Normal Battlefield'
}: {
  state?: BoardState;
  frameName?: string;
}) {
  const promptState = !['normal', 'dragging', 'selected'].includes(state) ? state as Exclude<BoardState, 'normal' | 'dragging' | 'selected'> : null;
  return <main data-mm-layer="MM.BoardRoot" className="mm-root relative">
      <div data-mm-layer="MM.BattlefieldSurface" className="mm-board-texture absolute mm-safe-frame rounded-[18px] border border-amber-300/28 shadow-[inset_0_0_70px_rgba(0,0,0,0.72)]" />
      <div className="mm-rune-line absolute left-[165px] top-[219px] h-px w-[560px]" />
      <div className="absolute left-[430px] top-[17px] text-center">
        <div className="mm-title text-[11px] font-semibold text-amber-200/90">MagicMobile</div>
        <div className="text-[7px] text-amber-100/45">{frameName}</div>
      </div>
      <OpponentHUD />
      <StatusPills state={state} />
      <StackIndicator active={state === 'stack' || state === 'dragging'} />
      <RightRail />
      <GameLog />
      <ZoneChips />
      <BattlefieldCards state={state} />
      <HandRail selected={state === 'selected'} />
      <div data-mm-layer="MM.CardInspectorSheet" className="mm-glass absolute bottom-[96px] left-5 z-20 w-[128px] rounded-md p-2 opacity-85">
        <div className="mm-title text-[9px] text-amber-200">Inspector</div>
        <div className="text-[7px] text-amber-100/65">Long press opens card info sheet</div>
      </div>
      {state === 'dragging' && <DropZones />}
      {promptState && <PromptOverlay state={promptState} />}
    </main>;
}
export const DraggingCardDropZonesVisible = () => {
  return <MagicMobileBoard state="dragging" frameName="Dragging Card / Drop Zones Visible" />;
};
